class RideSharingSystem {
    constructor() {
        this.riders = [];
        this.riderIdx = 0;
        this.drivers = [];
        this.driverIdx = 0;
        this.active = new Set();
    }
    addRider(riderId) {
        this.riders.push(riderId);
        this.active.add(riderId);
    }
    addDriver(driverId) {
        this.drivers.push(driverId);
    }
    matchDriverWithRider() {
        while (this.riderIdx < this.riders.length && !this.active.has(this.riders[this.riderIdx])) {
            this.riderIdx++;
        }
        if (this.riderIdx >= this.riders.length || this.driverIdx >= this.drivers.length) {
            return [-1, -1];
        }
        const rider = this.riders[this.riderIdx++];
        this.active.delete(rider);
        const driver = this.drivers[this.driverIdx++];
        return [driver, rider];
    }
    cancelRider(riderId) {
        this.active.delete(riderId);
    }
}
